import React, { useState } from 'react';
import { useDispatch } from 'react-redux';
import { loginSuccess } from '../store/authSlice';

function LoginPage({ onLogin }) {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [isRegistering, setIsRegistering] = useState(false);

  const dispatch = useDispatch();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      const url = isRegistering
        ? 'http://localhost:8080/area-backend/api/register'
        : 'http://localhost:8080/area-backend/api/login';

      const response = await fetch(url, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ username, password })
      });

      const data = await response.json();

      if (response.ok) {
        // Сохраняем в localStorage
        localStorage.setItem('token', data.token);
        localStorage.setItem('username', data.username || username);

        // Диспатчим успешный логин в Redux
        dispatch(loginSuccess({
          token: data.token,
          username: data.username || username
        }));

        // Вызываем callback
        onLogin();
      } else {
        setError(data.error ||
          (isRegistering ? 'Ошибка регистрации' : 'Ошибка авторизации'));
      }
    } catch (err) {
      setError('Ошибка соединения с сервером');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="login-container">
      <div className="login-box">
        <h1>Лабораторная работа №2</h1>
        <h2>Проверка попадания точки в область</h2>

        <div className="student-info">
          <p><strong>ФИО:</strong> Ваше ФИО</p>
          <p><strong>Группа:</strong> Ваша группа</p>
          <p><strong>Вариант:</strong> Ваш вариант</p>
        </div>

        <form onSubmit={handleSubmit} className="login-form">
          <h3>{isRegistering ? 'Регистрация' : 'Вход в систему'}</h3>

          <div className="form-group">
            <label htmlFor="username">Логин:</label>
            <input
              type="text"
              id="username"
              value={username}
              onChange={(e) => setUsername(e.target.value)}
              required
              disabled={loading}
              placeholder="Введите логин"
            />
          </div>

          <div className="form-group">
            <label htmlFor="password">Пароль:</label>
            <input
              type="password"
              id="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
              disabled={loading}
              placeholder="Введите пароль"
            />
          </div>

          {error && <div className="error-message">{error}</div>}

          <button
            type="submit"
            className="login-btn"
            disabled={loading}
          >
            {loading ? 'Обработка...' : (isRegistering ? 'Зарегистрироваться' : 'Войти')}
          </button>

          <button
            type="button"
            className="toggle-btn"
            onClick={() => setIsRegistering(!isRegistering)}
            disabled={loading}
          >
            {isRegistering ? 'Уже есть аккаунт? Войти' : 'Нет аккаунта? Зарегистрироваться'}
          </button>

          <div className="test-credentials">
            <p>Для тестирования можно использовать:</p>
            <p>admin / admin123</p>
            <p>Или регистрация</p>
          </div>
        </form>
      </div>
    </div>
  );
}

export default LoginPage;
